using namespace std;

long long solve(long long m, long long n, vector<vector<long long>> waitCost) {
    vector<vector<vector<long long>>> dp(m, vector<vector<long long>>(n, vector<long long>(2, LLONG_MAX)));
    long long entry_cost = (0 + 1) * (0 + 1);
    dp[0][0][1] = entry_cost;

    priority_queue<tuple<long long, int, int, int>, vector<tuple<long long, int, int, int>>, greater<>> pq;
    pq.push({entry_cost, 0, 0, 1});

    while (!pq.empty()) {
        auto [cost, i, j, p] = pq.top();
        pq.pop();

        if (i == m - 1 && j == n - 1) {
            return cost;
        }

        if (cost > dp[i][j][p]) {
            continue;
        }

        if (p == 1) {
            if (j + 1 < n) {
                long long new_cost = cost + (i + 1) * (j + 2);
                if (new_cost < dp[i][j + 1][0]) {
                    dp[i][j + 1][0] = new_cost;
                    pq.push({new_cost, i, j + 1, 0});
                }
            }
            if (i + 1 < m) {
                long long new_cost = cost + (i + 2) * (j + 1);
                if (new_cost < dp[i + 1][j][0]) {
                    dp[i + 1][j][0] = new_cost;
                    pq.push({new_cost, i + 1, j, 0});
                }
            }
        } else {
            long long new_cost = cost + waitCost[i][j];
            if (new_cost < dp[i][j][1]) {
                dp[i][j][1] = new_cost;
                pq.push({new_cost, i, j, 1});
            }
        }
    }

    return -1;
}

